SELECT *
FROM enterprise_talent_statistics
WHERE enterprise_id = #{enterpriseId}
  AND stat_date = #{statDate}
ORDER BY id DESC
LIMIT 1

SELECT *
FROM enterprise_talent_statistics
WHERE enterprise_id = #{enterpriseId}
  AND stat_date >= #{startDate}
  AND stat_date <= #{endDate}
ORDER BY stat_date ASC, id ASC
